#include <vector>
#include <algorithm>
using namespace std;

const long long mod = 1000000007;

const int B_size = 317;

class SegTree {
public:
    vector<long long> tree;
    vector<long long> lazy;
    int n;

    SegTree(int size) {
        n = size;
        tree.resize(4 * n, 1);
        lazy.resize(4 * n, 1);
    }

    void apply(int node, long long v) {
        tree[node] = (tree[node] * v) % mod;
        lazy[node] = (lazy[node] * v) % mod;
    }

    void push(int node) {
        if (lazy[node] != 1) {
            apply(2 * node, lazy[node]);
            apply(2 * node + 1, lazy[node]);
            lazy[node] = 1;
        }
    }

    void update_range(int node, int l, int r, int start, int end, long long v) {
        if (start > end) return;
        if (end < l || start > r) return;
        if (start <= l && r <= end) {
            apply(node, v);
            return;
        }
        push(node);
        int mid = (l + r) / 2;
        update_range(2 * node, l, mid, start, end, v);
        update_range(2 * node + 1, mid + 1, r, start, end, v);
    }

    void traverse(vector<long long>& res, int node, int l, int r) {
        if (l == r) {
            res[l] = tree[node];
            return;
        }
        push(node);
        int mid = (l + r) / 2;
        traverse(res, 2 * node, l, mid);
        traverse(res, 2 * node + 1, mid + 1, r);
    }
};

long long solve(vector<long long> nums, vector<vector<long long>> queries) {
    int n = nums.size();

    for (auto &q : queries) {
        long long l = q[0], r_bound = q[1], k = q[2], v = q[3];
        if (k > B_size) {
            for (long long idx = l; idx <= r_bound; idx += k) {
                if (idx < n) {
                    nums[idx] = (nums[idx] * v) % mod;
                }
            }
        }
    }

    vector<vector<vector<long long>>> small_queries(B_size + 1);
    for (int m = 0; m <= B_size; m++) {
        small_queries[m] = vector<vector<long long>>();
    }

    for (int m = 1; m <= B_size; m++) {
        small_queries[m] = vector<vector<long long>>(m);
    }

    for (auto &q : queries) {
        long long l_val = q[0], r_bound = q[1], k = q[2], v_val = q[3];
        if (k <= B_size) {
            long long residue = l_val % k;
            if (k > 0) {
                int mk = (int)k;
                int rr = (int)residue;
                if (rr < small_queries[mk].size()) {
                    small_queries[mk][rr].push_back({l_val, r_bound, v_val});
                }
            }
        }
    }

    for (int m = 1; m <= B_size; m++) {
        for (int r = 0; r < m; r++) {
            if (r >= n) continue;
            vector<vector<long long>>& queries_list = small_queries[m][r];
            if (queries_list.empty()) continue;
            int L = (n - 1 - r) / m + 1;

            SegTree st(L);
            for (auto &qvec : queries_list) {
                long long l_val = qvec[0], r_bound = qvec[1], v_val = qvec[2];
                long long j_low = (l_val >= r) ? (l_val - r) / m : 0;
                long long r_limit = min(r_bound, static_cast<long long>(n - 1));
                long long j_high = (r_limit - r) / m;
                if (j_high < 0) continue;
                if (j_low > j_high) continue;
                st.update_range(1, 0, L - 1, j_low, j_high, v_val);
            }

            vector<long long> leaves(L, 1);
            st.traverse(leaves, 1, 0, L - 1);
            for (int j = 0; j < L; j++) {
                long long index_val = r + static_cast<long long>(j) * m;
                if (index_val < n) {
                    nums[index_val] = (nums[index_val] * leaves[j]) % mod;
                }
            }
        }
    }

    long long ans = 0;
    for (long long num : nums) {
        ans ^= num;
    }
    return ans;
}
