        int v = (int)(v_orig % MOD);
        if (k_val > K) {
            for (long long idx = l; idx <= r; idx += k_val) {
                if (idx < n) {
                    large_factor[(int)idx] = (large_factor[(int)idx] * v) % MOD;
                }
                else break;
            }
        } else {
            if (k_val >= 1 && k_val <= K) {
                queries_by_k[(int)k_val].push_back({l, r, (long long)v});
            }
        }
    }

    vector<vector<SegTree>> seg_trees(K + 1);
    for (int k = 1; k <= K; k++) {
        if (queries_by_k[k].size() == 0) 
            continue;
        seg_trees[k] = vector<SegTree>();
        for (int r = 0; r < k; r++) {
            int size = residues[k][r].size();
            seg_trees[k].push_back(SegTree(size));
        }
    }

    for (int k = 1; k <= K; k++) {
        if (queries_by_k[k].size() == 0) 
            continue;
        for (auto& qry : queries_by_k[k]) {
            long long l = qry[0];
            long long r_val = qry[1];
            int v = (int)qry[2];
            int k_val = k;
            int r0 = (int)(l % k_val);
            const vector<int>& arr = residues[k][r0];
            int size = arr.size();
            if (size == 0) 
                continue;
            int l_int = (int)l;
            int r_int = (int)r_val;
            auto it_low = lower_bound(arr.begin(), arr.end(), l_int);
            if (it_low == arr.end()) 
                continue;
            int low_index = it_low - arr.begin();
            auto it_high = upper_bound(arr.begin(), arr.end(), r_int);
            if (it_high == arr.begin()) 
                continue;
            it_high--;
            int high_index = it_high - arr.begin();
            if (low_index > high_index) 
                continue;
            seg_trees[k][r0].update(low_index, high_index, v);
        }
    }

    for (int k = 1; k <= K; k++) {
        if (queries_by_k[k].size() == 0) 
            continue;
        for (int r = 0; r < k; r++) {
            if (residues[k][r].size() == 0) 
                continue;
            seg_trees[k][r].gather(small_factor, residues[k][r]);
        }
    }

    long long ans = 0;
    for (int i = 0; i < n; i++) {
        int temp = (nums[i] % MOD);
        int factor_i = (small_factor[i] * large_factor[i]) % MOD;
        int x = (temp * factor_i) % MOD;
        ans ^= x;
    }

    return ans;
}
```

### Explanation
1. **SegTree Class**: This class implements a segment tree with lazy propagation to handle range multiplicative updates efficiently. Each node stores the product of updates in its range, and lazy propagation ensures updates are applied only when necessary.
2. **Residue Handling**: For each step size `k` (up to a threshold K), indices are grouped by their residue modulo `k`. This transforms the problem of updating arithmetic progressions into updating contiguous segments in these residue groups.
3. **Query Processing**:
   - **Large Step Queries (k > K)**: These are processed directly by iterating over the affected indices, leveraging the fact that each query updates only a few elements.
   - **Small Step Queries (k ≤ K)**: These are processed using segment trees on residue groups. Each query updates a contiguous segment in the residue group, handled efficiently by the segment tree.
4. **Combining Results**: After processing all queries, the combined multiplicative factor for each element is computed by multiplying contributions from both small and large step queries. The final array element is derived by applying this factor to the initial value modulo 116.
5. **XOR Calculation**: The XOR of all modified array elements is computed and returned as the result.

This approach efficiently handles the constraints by leveraging residue grouping and segment trees for small step updates, combined with direct processing for large step updates, ensuring optimal performance.
